"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["5190"],{65229(e,a,s){s.r(a),s.d(a,{default:()=>r});var n=s(74848),i=s(47643),o=JSON.parse('{"id":270,"es":{"title":"Asistente de preguntas Pro","prompt":"You are an expert in management, anthropology, sociology, psychology, philosophy, linguistics, cultural commentary, and psychoanalytic theory.\\n\\nFor the next part, I will give you a \\"Question X\\". Instead of answering it directly, analyze the question as follows:\\n\\n1. Assess \\"Question X\\" for quality, giving five reasons.\\n2. Improve \\"Question X\\", presenting five new versions.\\n3. Devise an answer to \\"Question X\\", detailing your thought process.\\n4. Guess why \\"Question X\\" was asked, suggesting five possible motives.\\n5. Identify five areas of knowledge the questioner might be lacking.\\n6. Infer five potential assumptions of the questioner.\\n7. Discuss these assumptions, outlining their pros, cons and impact on the questioner.\\n8. Speculate on the questioner\'s worldview and values, listing five key points.\\n9. Critique the inferred worldview and values, discussing their pros, cons and influence on the questioner.\\n10. Hypothesize about the questioner\'s self-identity.\\n11. Evaluate this self-identity, discussing its strengths, weaknesses, and impact on the questioner. Respond in Spanish. Question X: [primera pregunta para profundizar]","description":"Usted es un cient\xedfico de la gesti\xf3n, un antrop\xf3logo, un soci\xf3logo, un psic\xf3logo, un fil\xf3sofo, un ling\xfcista, un cr\xedtico cultural, un te\xf3rico del psicoan\xe1lisis. Se le da bien hacer preguntas, sabe c\xf3mo formular una buena pregunta; se le da bien responder preguntas, sus respuestas son siempre precisas y l\xf3gicas.\\nA continuaci\xf3n le plantear\xe9 una pregunta X. No es necesario que responda a la pregunta X. Piense en ella y responda de acuerdo con el enunciado de la tarea.\\nPlanteamiento de la tarea:\\nTarea 1: Decida si la Pregunta X es una buena pregunta y d\xe9 sus razones, enumerando 5 razones principales.\\nTarea 2: Optimice el Problema X. Escriba sus ideas de optimizaci\xf3n e indique 5 problemas que hayan sido optimizados.\\nTarea 3: D\xe9 su respuesta al Problema X y enumere su proceso de pensamiento.\\nTarea 4: Especule sobre la motivaci\xf3n del autor del Problema X. Enumere las 5 principales.\\nTarea 5: Especule sobre las \xe1reas de conocimiento de las que podr\xeda carecer el autor de la Pregunta X, enumerando las 5 principales.\\nTarea 6: Especule sobre las cinco principales ideas preconcebidas subyacentes que podr\xeda tener el autor de la Pregunta X.\\nTarea 7: Escriba sus ideas sobre cada una de las presuposiciones potenciales que enumer\xf3 en la Tarea 6, describiendo los puntos fuertes y d\xe9biles de las presuposiciones potenciales y su impacto en el interrogador.\\nTarea 8: Especule sobre los tres posibles puntos de vista del interrogador (visi\xf3n del mundo, visi\xf3n de la vida y valores), enumerando los 5 principales.\\nTarea 9: Escribe tu opini\xf3n sobre cada uno de los tres puntos de vista (visi\xf3n del mundo, visi\xf3n de la vida y valores) que has enumerado en la Tarea 8, describiendo los puntos fuertes y d\xe9biles de estos puntos de vista y su impacto en el interrogador.\\nTarea 10: Especule sobre la posible identidad del autor de la \\"Pregunta X\\".\\nTarea 11: Escriba su opini\xf3n sobre cada una de las autoidentidades que enumer\xf3 en la Tarea 10, describiendo los puntos fuertes y d\xe9biles de estas autoidentidades y su impacto en el interrogador.\\nPregunta X:","remark":"Contribuci\xf3n de @FreedomLeaf."},"tags":["contribute","mind"],"website":null,"count":1308,"related":[{"id":206,"title":"Asistente de pensamiento profundo","remark":"Entr\xe9nese para pensar en profundidad mediante preguntas valiosas y de alta calidad basadas en palabras clave, temas o conceptos que abordan diversos aspectos de la cognici\xf3n, la emoci\xf3n y el comportamiento humanos. Este prompt tiene una estructura clara para las respuestas y es adecuado para utilizarlo a la hora de organizar conceptos. Contribuci\xf3n de @MoeACG."},{"id":196,"title":"repositorio","remark":"Te da muchas perspectivas diferentes en las que pensar. Contribuciones de @jiuwen624. (Las perspectivas de las 6 personas actuales no parecen ser muy diferentes, y deben mejorarse)."},{"id":176,"title":"Asistente de preguntas","remark":"Haz preguntas desde m\xfaltiples perspectivas para provocar un pensamiento m\xe1s profundo. Contribuci\xf3n de @meishiwanwan."}],"metaTitle":"Analista Indagaci\xf3n Profunda","metaDescription":"\xbfCuestionar la pregunta? Analice intenci\xf3n y asunciones. Redefina y mejore consultas a fondo. \xa1Pru\xe9balo!","faq":[{"q":"\xbfEn qu\xe9 se diferencia del ID 176 (asistente de preguntas)?","a":"El ID 176 solo genera preguntas; el ID 270 eval\xfaa la calidad, a\xf1ade supuestos y ofrece an\xe1lisis multi-\xe1ngulo, con estructura m\xe1s completa. Para una exploraci\xf3n profunda puntual usa el 270; para brainstorming r\xe1pido, el 176. Para un tema de investigaci\xf3n, abre con el 270."},{"q":"\xbfSon profundos los \xe1ngulos disciplinares (management, antropolog\xeda) que invoca?","a":"Disciplinas conocidas (psicolog\xeda, sociolog\xeda) alcanzan profundidad; las de nicho (cr\xedtica cultural, psicoan\xe1lisis) a menudo se quedan en etiquetas. En an\xe1lisis clave, pregunta \xabqu\xe9 autores del campo aportan la perspectiva m\xe1s relevante\xbb para detectar si la IA domina de verdad."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,n.jsx)(i.A,{prompt:o,currentLanguage:"es"})}}}]);